// --- Socket.io authentication middleware ---
io.use((socket, next) => {
  const token = socket.handshake.auth?.token;
  if (!token) {
    return next(new Error('Authentication required. Provide a session token.'));
  }

  const session = validateSession(token);
  if (!session) {
    return next(new Error('Invalid or expired session. Please log in again.'));
  }

  // Check if user already has an active socket connection
  for (const [existingSocketId, existingData] of activeSockets.entries()) {
    if (existingData.username === session.username) {
      // Disconnect the old socket
      const existingSocket = io.sockets.sockets.get(existingSocketId);
      if (existingSocket) {
        existingSocket.emit('error_message', { message: 'Session taken over by new connection.' });
        existingSocket.disconnect(true);
      }
      activeSockets.delete(existingSocketId);
    }
  }

  // Attach session data to socket
  socket.username = session.username;
  socket.sessionToken = token;
  next();
});

// --- Socket.io connection handling ---
io.on('connection', (socket) => {
  const username = socket.username;
  console.log(`Player connected: ${username} (socket: ${socket.id})`);

  activeSockets.set(socket.id, {
    username,
    sessionToken: socket.sessionToken
  });

  // Ensure player state exists
  if (!playerStates.has(username)) {
    initializePlayerState(username);
  }

  const state = playerStates.get(username);

  // Send current state to player
  socket.emit('game_state', {
    username,
    score: state.score,
    position: state.position,
    leaderboard: getLeaderboard()
  });

  // Broadcast player joined
  socket.broadcast.emit('player_joined', { username });

  // --- Handle game actions (SERVER-AUTHORITATIVE) ---
  socket.on('game_action', (data) => {
    // Re-validate session on each action
    const session = validateSession(socket.sessionToken);
    if (!session) {
      socket.emit('error_message', { message: 'Session expired. Please re-authenticate.' });
      socket.disconnect(true);
      return;
    }

    // Rate limiting
    if (isRateLimited(username)) {
      socket.emit('error_message', { message: 'Rate limited. Slow down.' });
      return;
    }

    // Validate action data structure
    if (!data || typeof data !== 'object' || typeof data.type !== 'string') {
      socket.emit('error_message', { message: 'Invalid action format.' });
      return;
    }

    // Validate and apply action server-side
    const result = validateAndApplyAction(username, data);

    if (!result.valid) {
      console.warn(`Invalid action from ${username}: ${result.reason}`, data);
      socket.emit('action_rejected', {
        reason: result.reason,
        action: data.type
      });
      return;
    }

    // Send validated result back to player
    socket.emit('action_result', {
      type: data.type,
      score: result.newScore,
      increment: result.increment,
      serverTimestamp: Date.now()
    });

    // Update leaderboard with server-validated score
    updateLeaderboard(username, result.newScore);

    // Broadcast updated state to other players
    socket.broadcast.emit('player_update', {
      username,
      score: result.newScore,
      position: playerStates.get(username)?.position
    });
  });

  // --- Handle score submission (for game end / checkpoint) ---
  // NOTE: We do NOT trust client-reported scores. We use server-tracked scores.
  socket.on('submit_score', (data) => {
    const session = validateSession(socket.sessionToken);
    if (!session) {
      socket.emit('error_message', { message: 'Session expired.' });
      socket.disconnect(true);
      return;
    }

    const serverState = playerStates.get(username);
    if (!serverState) {
      socket.emit('error_message', { message: 'No game state found.' });
      return;
    }

    // Use SERVER-TRACKED score, not client-reported score
    const serverScore = serverState.score;

    // Log if client score differs significantly (potential cheat attempt)
    if (data && typeof data.score === 'number') {
      const clientScore = data.score;
      if (Math.abs(clientScore - serverScore) > 10) {
        console.warn(
          `Score mismatch for ${username}: client=${clientScore}, server=${serverScore}. Using server score.`
        );
      }
    }

    updateLeaderboard(username, serverScore);

    socket.emit('score_submitted', {
      score: serverScore,
      leaderboard: getLeaderboard()
    });

    // Broadcast leaderboard update
    io.emit('leaderboard_update', { leaderboard: getLeaderboard() });
  });

  // --- Request leaderboard ---
  socket.on('get_leaderboard', () => {
    socket.emit('leaderboard_update', { leaderboard: getLeaderboard() });
  });

  // --- Handle disconnect ---
  socket.on('disconnect', (reason) => {
    console.log(`Player disconnected: ${username} (reason: ${reason})`);
    activeSockets.delete(socket.id);
    socket.broadcast.emit('player_left', { username });
  });

  // --- Periodic session validation ---
  const sessionCheckInterval = setInterval(() => {
    const session = validateSession(socket.sessionToken);
    if (!session) {
      socket.emit('error_message', { message: 'Session expired. Please re-authenticate.' });
      socket.disconnect(true);
      clearInterval(sessionCheckInterval);
    }
  }, 60000); // Check every minute

  socket.on('disconnect', () => {
    clearInterval(sessionCheckInterval);
  });
});

// --- Session cleanup (run periodically) ---
setInterval(() => {
  const now = Date.now();
  for (const [token, session] of sessions.entries()) {
    if (now > session.expiresAt) {
      sessions.delete(token);
    }
  }
}, 5 * 60 * 1000); // Every 5 minutes

